### ast-grep CLI Scanner

```rust
pub struct AstGrepCliScanner {
    /// Path to ast-grep binary
    binary_path: PathBuf,
    /// Pattern rules directory
    rules_dir: PathBuf,
    /// Timeout for scanning
    timeout: Duration,
}

impl AstGrepCliScanner {
    pub fn new() -> Result<Self, ScannerError> {
        // Find ast-grep binary
        let binary_path = which::which("ast-grep")
            .or_else(|_| which::which("sg"))
            .map_err(|_| ScannerError::BinaryNotFound)?;

        Ok(Self {
            binary_path,
            rules_dir: default_rules_dir(),
            timeout: Duration::from_millis(500),
        })
    }
}

impl HeredocScanner for AstGrepCliScanner {
    fn scan(&self, content: &str, language: Language) -> ScanResult {
        let lang_name = match language.grammar_name() {
            Some(n) => n,
            None => return ScanResult::empty(), // Unknown language, skip
        };

        // Write content to temp file
        let temp_file = tempfile::NamedTempFile::with_suffix(&format!(".{}", lang_name))?;
        std::fs::write(temp_file.path(), content)?;

        // Invoke ast-grep
        let output = Command::new(&self.binary_path)
            .args([
                "scan",
                "--lang", lang_name,
                "--rule", &self.rules_dir.join(format!("{}.yml", lang_name)).to_string_lossy(),
                "--json",
                temp_file.path().to_str().unwrap(),
            ])
            .timeout(self.timeout)
            .output()?;

        // Parse JSON output
        parse_ast_grep_output(&output.stdout)
    }
}
```

